import * as fs from "node:fs";
import * as path from "node:path";
import type { ReviewExtensionConfig, PerspectiveConfig, QualityConfig, AutoReviewConfig, Severity } from "./types.ts";

const DEFAULT_PERSPECTIVE_SEVERITY: Record<string, Severity> = {
	security: "must-fix",
	performance: "should-fix",
	maintainability: "should-fix",
	style: "nice-to-have",
	testing: "should-fix",
	production: "should-fix",
};

function defaultPerspectives(): Record<string, PerspectiveConfig> {
	const entries = Object.entries(DEFAULT_PERSPECTIVE_SEVERITY);
	const result: Record<string, PerspectiveConfig> = {};
	for (const [name, severity] of entries) {
		result[name] = { enabled: name !== "production", severity };
	}
	return result;
}

const DEFAULT_QUALITY: QualityConfig = {
	rejectGeneric: true,
	requireEvidence: true,
	minFindingsPerFile: 1,
};

const DEFAULT_AUTO_REVIEW: AutoReviewConfig = {
	onEdit: false,
	onCommit: true,
	onPR: true,
};

export const DEFAULT_CONFIG: ReviewExtensionConfig = {
	enabled: true,
	perspectives: defaultPerspectives(),
	quality: { ...DEFAULT_QUALITY },
	autoReview: { ...DEFAULT_AUTO_REVIEW },
};

export function loadConfig(cwd: string): { config: ReviewExtensionConfig; source: "file" | "defaults" } {
	const configPath = path.join(cwd, ".pi", "pi-review.json");

	if (!fs.existsSync(configPath)) {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}

	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed: unknown = JSON.parse(raw);

		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
		}

		const user = parsed as Record<string, unknown>;
		const config = structuredClone(DEFAULT_CONFIG);

		if (typeof user.enabled === "boolean") {
			config.enabled = user.enabled;
		}

		if (typeof user.perspectives === "object" && user.perspectives !== null && !Array.isArray(user.perspectives)) {
			const perspectives = user.perspectives as Record<string, unknown>;
			for (const [name, value] of Object.entries(perspectives)) {
				if (typeof value === "object" && value !== null && !Array.isArray(value)) {
					const p = value as Record<string, unknown>;
					config.perspectives[name] = {
						enabled: typeof p.enabled === "boolean" ? p.enabled : true,
						severity: typeof p.severity === "string" ? (p.severity as Severity) : DEFAULT_PERSPECTIVE_SEVERITY[name] ?? "should-fix",
					};
				}
			}
		}

		if (typeof user.quality === "object" && user.quality !== null && !Array.isArray(user.quality)) {
			const q = user.quality as Record<string, unknown>;
			if (typeof q.rejectGeneric === "boolean") config.quality.rejectGeneric = q.rejectGeneric;
			if (typeof q.requireEvidence === "boolean") config.quality.requireEvidence = q.requireEvidence;
			if (typeof q.minFindingsPerFile === "number") config.quality.minFindingsPerFile = q.minFindingsPerFile;
		}

		if (typeof user.autoReview === "object" && user.autoReview !== null && !Array.isArray(user.autoReview)) {
			const a = user.autoReview as Record<string, unknown>;
			if (typeof a.onEdit === "boolean") config.autoReview.onEdit = a.onEdit;
			if (typeof a.onCommit === "boolean") config.autoReview.onCommit = a.onCommit;
			if (typeof a.onPR === "boolean") config.autoReview.onPR = a.onPR;
		}

		return { config, source: "file" };
	} catch {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}
}

import { SEVERITY_ORDER, SEVERITY_BADGES, type Severity } from "../types.ts";

export function compareSeverity(a: Severity, b: Severity): number {
	return SEVERITY_ORDER[b] - SEVERITY_ORDER[a];
}

export function severityBadge(severity: Severity): string {
	return `${SEVERITY_BADGES[severity]} ${severity}`;
}

export function severityLabel(severity: Severity): string {
	return `${SEVERITY_BADGES[severity]} ${severity.toUpperCase()}`;
}

export function sortSeverities(severities: Severity[]): Severity[] {
	return [...severities].sort(compareSeverity);
}

export function isHighSeverity(severity: Severity): boolean {
	return SEVERITY_ORDER[severity] >= 3;
}

export function allSeverities(): Severity[] {
	return ["must-fix", "should-fix", "nice-to-have", "info"];
}

import type { ReviewFinding, Severity, ReviewSummary } from "../types.ts";

export function createFinding(
	file: string,
	line: number,
	severity: Severity,
	category: string,
	title: string,
	description: string,
	evidence: string,
	suggestion: string,
): ReviewFinding {
	return { file, line, severity, category, title, description, evidence, suggestion };
}

export function validateFinding(finding: ReviewFinding): { valid: boolean; errors: string[] } {
	const errors: string[] = [];

	if (!finding.file || typeof finding.file !== "string") {
		errors.push("Finding must have a non-empty 'file' field.");
	}
	if (typeof finding.line !== "number" || finding.line < 0) {
		errors.push("Finding must have a non-negative 'line' number.");
	}
	if (!finding.severity || !["must-fix", "should-fix", "nice-to-have", "info"].includes(finding.severity)) {
		errors.push(`Finding has invalid severity: '${finding.severity}'.`);
	}
	if (!finding.category || typeof finding.category !== "string") {
		errors.push("Finding must have a non-empty 'category' field.");
	}
	if (!finding.title || typeof finding.title !== "string") {
		errors.push("Finding must have a non-empty 'title' field.");
	}
	if (!finding.description || typeof finding.description !== "string") {
		errors.push("Finding must have a non-empty 'description' field.");
	}
	if (!finding.evidence || typeof finding.evidence !== "string") {
		errors.push("Finding must have a non-empty 'evidence' field.");
	}
	if (!finding.suggestion || typeof finding.suggestion !== "string") {
		errors.push("Finding must have a non-empty 'suggestion' field.");
	}

	return { valid: errors.length === 0, errors };
}

export function findingsByFile(findings: ReviewFinding[]): Record<string, ReviewFinding[]> {
	const map: Record<string, ReviewFinding[]> = {};
	for (const f of findings) {
		if (!map[f.file]) map[f.file] = [];
		map[f.file]!.push(f);
	}
	return map;
}

export function findingsBySeverity(findings: ReviewFinding[]): Record<Severity, ReviewFinding[]> {
	const map: Record<Severity, ReviewFinding[]> = {
		"must-fix": [],
		"should-fix": [],
		"nice-to-have": [],
		info: [],
	};
	for (const f of findings) {
		if (map[f.severity]) {
			map[f.severity]!.push(f);
		}
	}
	return map;
}

export function findingsByCategory(findings: ReviewFinding[]): Record<string, ReviewFinding[]> {
	const map: Record<string, ReviewFinding[]> = {};
	for (const f of findings) {
		if (!map[f.category]) map[f.category] = [];
		map[f.category]!.push(f);
	}
	return map;
}

export function buildSummary(findings: ReviewFinding[], perspectives: string[]): ReviewSummary {
	const bySeverity: Record<Severity, number> = { "must-fix": 0, "should-fix": 0, "nice-to-have": 0, info: 0 };
	const byCategory: Record<string, number> = {};
	const byFile: Record<string, number> = {};

	for (const f of findings) {
		bySeverity[f.severity]++;
		byCategory[f.category] = (byCategory[f.category] ?? 0) + 1;
		byFile[f.file] = (byFile[f.file] ?? 0) + 1;
	}

	return {
		total: findings.length,
		bySeverity,
		byCategory,
		byFile,
	};
}

import type { PerspectiveDefinition, DiffHunk } from "../types.ts";

class PerspectiveRegistry {
	private perspectives = new Map<string, PerspectiveDefinition>();

	register(definition: PerspectiveDefinition): void {
		this.perspectives.set(definition.name, definition);
	}

	get(name: string): PerspectiveDefinition | undefined {
		return this.perspectives.get(name);
	}

	list(): PerspectiveDefinition[] {
		return [...this.perspectives.values()];
	}

	names(): string[] {
		return [...this.perspectives.keys()];
	}

	filterByNames(names?: string[]): PerspectiveDefinition[] {
		if (!names || names.length === 0) {
			return this.list();
		}
		return names
			.map((n) => this.perspectives.get(n))
			.filter((p): p is PerspectiveDefinition => p !== undefined);
	}

	buildPromptContext(perspective: PerspectiveDefinition, hunks: DiffHunk[]): string {
		const lines: string[] = [];
		lines.push(`## ${perspective.label} Review (${perspective.name})`);
		lines.push(perspective.description);
		lines.push("");
		lines.push("### Checklist:");
		for (const item of perspective.checklist) {
			lines.push(`- [ ] ${item}`);
		}
		if (perspective.threatModel) {
			lines.push("");
			lines.push("### Threat Model:");
			for (const [category, items] of Object.entries(perspective.threatModel)) {
				lines.push(`**${category}:**`);
				for (const item of items) {
					lines.push(`  - ${item}`);
				}
			}
		}
		if (hunks.length > 0) {
			lines.push("");
			lines.push("### Changed Files:");
			const files = [...new Set(hunks.map((h) => h.file))];
			for (const file of files) {
				const fileHunks = hunks.filter((h) => h.file === file);
				lines.push(`- ${file} (${fileHunks.length} hunks)`);
			}
		}
		return lines.join("\n");
	}

	clear(): void {
		this.perspectives.clear();
	}
}

// Singleton registry
export const registry = new PerspectiveRegistry();

