import { spawn } from "node:child_process";

export interface GitDiffOptions {
	base?: string;
	head?: string;
	cwd: string;
	maxFiles?: number;
}

export async function extractDiff(options: GitDiffOptions): Promise<string> {
	const { cwd, base, head, maxFiles = 20 } = options;

	const args = ["diff", "--unified=5"];
	if (base && head) {
		args.push(`${base}...${head}`);
	} else if (base) {
		args.push(base);
	} else {
		// Default: staged + unstaged changes vs HEAD
		args.push("HEAD");
	}

	const result = await runGit(args, cwd);

	if (result.exitCode !== 0 && !result.stdout) {
		throw new Error(`git diff failed (exit ${result.exitCode}): ${result.stderr}`);
	}

	// Limit files if needed
	if (maxFiles > 0) {
		return limitFiles(result.stdout, maxFiles);
	}

	return result.stdout;
}

export async function extractFileDiff(cwd: string, file: string, base?: string): Promise<string> {
	const args = ["diff", "--unified=5"];
	if (base) {
		args.push(base);
	} else {
		args.push("HEAD");
	}
	args.push("--", file);

	const result = await runGit(args, cwd);
	return result.stdout;
}

function limitFiles(diff: string, maxFiles: number): string {
	const files: string[] = [];
	const lines = diff.split("\n");
	const output: string[] = [];
	let currentFileOutput: string[] = [];
	let inFile = false;

	for (const line of lines) {
		if (line.startsWith("diff --git")) {
			if (inFile && files.length < maxFiles) {
				output.push(...currentFileOutput);
			}
			if (files.length >= maxFiles) {
				output.push(`\n... (truncated: showing first ${maxFiles} files)`);
				return output.join("\n");
			}
			const match = line.match(/^diff --git a\/(.+?) b\/(.+)$/);
			if (match) {
				files.push(match[2]!);
			}
			currentFileOutput = [line];
			inFile = true;
		} else if (inFile) {
			currentFileOutput.push(line);
		}
	}

	if (inFile && files.length <= maxFiles) {
		output.push(...currentFileOutput);
	}

	return output.join("\n");
}

function runGit(args: string[], cwd: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
	return new Promise((resolve) => {
		const proc = spawn("git", args, { cwd, stdio: ["ignore", "pipe", "pipe"] });
		const stdoutChunks: Buffer[] = [];
		const stderrChunks: Buffer[] = [];

		proc.stdout.on("data", (chunk: Buffer) => stdoutChunks.push(chunk));
		proc.stderr.on("data", (chunk: Buffer) => stderrChunks.push(chunk));

		proc.on("close", (code) => {
			resolve({
				stdout: Buffer.concat(stdoutChunks).toString("utf-8"),
				stderr: Buffer.concat(stderrChunks).toString("utf-8"),
				exitCode: code ?? 0,
			});
		});

		proc.on("error", (err) => {
			resolve({ stdout: "", stderr: err.message, exitCode: 1 });
		});
	});
}

import type { DiffHunk, ChangeType } from "../types.ts";

const DIFF_HEADER_RE = /^diff --git a\/(.+?) b\/(.+)$/;
const HUNK_HEADER_RE = /^@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@(.*)$/;
const NEW_FILE_RE = /^new file mode /;
const DELETED_FILE_RE = /^deleted file mode /;
const RENAME_FROM_RE = /^rename from (.+)$/;
const RENAME_TO_RE = /^rename to (.+)$/;

export interface ParsedDiff {
	file: string;
	oldFile: string;
	changeType: ChangeType;
	hunks: DiffHunk[];
}

export function classifyChanges(diff: string): ParsedDiff[] {
	if (!diff || !diff.trim()) return [];

	const results: ParsedDiff[] = [];
	let current: ParsedDiff | undefined;
	let currentHunk: DiffHunk | undefined;
	let hunkContent: string[] = [];

	const lines = diff.split("\n");

	for (const line of lines) {
		const headerMatch = line.match(DIFF_HEADER_RE);
		if (headerMatch) {
			// Save previous hunk
			if (currentHunk) {
				currentHunk.content = hunkContent.join("\n");
			}
			if (current) {
				results.push(current);
			}

			const oldFile = headerMatch[1]!;
			const newFile = headerMatch[2]!;
			current = {
				file: newFile,
				oldFile,
				changeType: "modified",
				hunks: [],
			};
			hunkContent = [];
			currentHunk = undefined;
			continue;
		}

		if (!current) continue;

		// Detect change type from metadata
		if (NEW_FILE_RE.test(line)) {
			current.changeType = "new";
		} else if (DELETED_FILE_RE.test(line)) {
			current.changeType = "deleted";
		} else if (RENAME_FROM_RE.test(line) || RENAME_TO_RE.test(line)) {
			current.changeType = "renamed";
		}

		// Parse hunk headers
		const hunkMatch = line.match(HUNK_HEADER_RE);
		if (hunkMatch) {
			// Save previous hunk
			if (currentHunk) {
				currentHunk.content = hunkContent.join("\n");
				current.hunks.push(currentHunk);
			}

			hunkContent = [];
			currentHunk = {
				file: current.file,
				changeType: current.changeType,
				oldStart: parseInt(hunkMatch[1]!, 10),
				oldCount: parseInt(hunkMatch[2] ?? "1", 10),
				newStart: parseInt(hunkMatch[3]!, 10),
				newCount: parseInt(hunkMatch[4] ?? "1", 10),
				content: "",
				header: hunkMatch[5]?.trim() ?? "",
			};
			continue;
		}

		// Collect hunk content
		if (currentHunk && (line.startsWith("+") || line.startsWith("-") || line.startsWith(" ") || line.startsWith("\\ "))) {
			hunkContent.push(line);
		}
	}

	// Save last hunk
	if (currentHunk) {
		currentHunk.content = hunkContent.join("\n");
		current.hunks.push(currentHunk);
	}
	if (current) {
		results.push(current);
	}

	return results;
}

export function allHunks(parsed: ParsedDiff[]): DiffHunk[] {
	return parsed.flatMap((p) => p.hunks);
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { DiffHunk, ExtractedContext } from "../types.ts";

export function extractContext(
	file: string,
	hunks: DiffHunk[],
	cwd: string,
	linesBefore = 5,
	linesAfter = 5,
): ExtractedContext[] {
	const filePath = path.resolve(cwd, file);

	if (!fs.existsSync(filePath)) {
		return [];
	}

	let fileContent: string;
	try {
		fileContent = fs.readFileSync(filePath, "utf-8");
	} catch {
		return [];
	}

	const fileLines = fileContent.split("\n");
	const results: ExtractedContext[] = [];

	for (let i = 0; i < hunks.length; i++) {
		const hunk = hunks[i]!;
		const hunkStart = hunk.newStart;
		const hunkEnd = hunkStart + hunk.newCount - 1;

		// Extract context lines
		const beforeStart = Math.max(0, hunkStart - 1 - linesBefore);
		const beforeEnd = Math.max(0, hunkStart - 1);
		const afterStart = Math.min(fileLines.length, hunkEnd);
		const afterEnd = Math.min(fileLines.length, hunkEnd + linesAfter);

		const beforeLines = fileLines.slice(beforeStart, beforeEnd);
		const hunkLines = fileLines.slice(Math.max(0, hunkStart - 1), Math.min(fileLines.length, hunkEnd));
		const afterLines = fileLines.slice(afterStart, afterEnd);

		results.push({
			file,
			hunkIndex: i,
			beforeLines,
			hunkLines,
			afterLines,
			startLine: beforeStart + 1,
		});
	}

	return results;
}

import type { DiffHunk, ImpactAssessment } from "../types.ts";

const CRITICAL_PATHS = [
	/auth/i,
	/security/i,
	/config/i,
	/env/i,
	/secret/i,
	/password/i,
	/token/i,
	/session/i,
	/middleware/i,
	/route/i,
	/api/i,
	/\.env/i,
	/permission/i,
	/privilege/i,
	/admin/i,
	/root/i,
];

export function calculateImpact(hunks: DiffHunk[]): ImpactAssessment {
	const fileSet = new Set<string>();
	let linesAdded = 0;
	let linesRemoved = 0;
	const highImpactFiles: string[] = [];
	const criticalPaths: string[] = [];

	for (const hunk of hunks) {
		fileSet.add(hunk.file);

		const contentLines = hunk.content.split("\n");
		for (const line of contentLines) {
			if (line.startsWith("+") && !line.startsWith("+++")) linesAdded++;
			if (line.startsWith("-") && !line.startsWith("---")) linesRemoved++;
		}
	}

	// Check for critical paths
	for (const file of fileSet) {
		if (CRITICAL_PATHS.some((re) => re.test(file))) {
			criticalPaths.push(file);
		}
	}

	// Large changes are high impact
	const filesChanged = fileSet.size;
	const totalChanges = linesAdded + linesRemoved;
	const filesByChanges = new Map<string, number>();

	for (const hunk of hunks) {
		const contentLines = hunk.content.split("\n");
		let changes = 0;
		for (const line of contentLines) {
			if (line.startsWith("+") || line.startsWith("-")) changes++;
		}
		filesByChanges.set(hunk.file, (filesByChanges.get(hunk.file) ?? 0) + changes);
	}

	// Files with > 50 lines changed are high impact
	for (const [file, count] of filesByChanges) {
		if (count > 50) {
			highImpactFiles.push(file);
		}
	}

	// Critical path files are also high impact
	for (const file of criticalPaths) {
		if (!highImpactFiles.includes(file)) {
			highImpactFiles.push(file);
		}
	}

	return {
		filesChanged,
		linesAdded,
		linesRemoved,
		highImpactFiles,
		criticalPaths,
	};
}

export function formatImpact(impact: ImpactAssessment): string {
	const lines: string[] = [];
	lines.push(`📊 **Impact Assessment**`);
	lines.push(`- Files changed: ${impact.filesChanged}`);
	lines.push(`- Lines added: +${impact.linesAdded}`);
	lines.push(`- Lines removed: -${impact.linesRemoved}`);

	if (impact.criticalPaths.length > 0) {
		lines.push(`- ⚠️ Critical paths: ${impact.criticalPaths.join(", ")}`);
	}

	if (impact.highImpactFiles.length > 0) {
		lines.push(`- 🔥 High impact files: ${impact.highImpactFiles.join(", ")}`);
	}

	return lines.join("\n");
}

import type { ReviewFinding } from "../types.ts";

export const GENERIC_PHRASES = [
	"looks good to me",
	"LGTM",
	"seems fine",
	"nice work",
	"no issues found",
	"code is clean",
	"everything looks correct",
	"i don't see any problems",
	"no comments",
	"ship it",
];

export function isGenericReview(reviewText: string): boolean {
	const normalized = reviewText.toLowerCase().trim();
	return GENERIC_PHRASES.some((phrase) => normalized.includes(phrase.toLowerCase()))
		&& reviewText.length < 200;
}

export function rejectGenericFindings(findings: ReviewFinding[]): {
	valid: ReviewFinding[];
	rejected: ReviewFinding[];
} {
	const valid: ReviewFinding[] = [];
	const rejected: ReviewFinding[] = [];

	for (const finding of findings) {
		const text = `${finding.title} ${finding.description}`;
		if (isGenericReview(text)) {
			rejected.push(finding);
		} else {
			valid.push(finding);
		}
	}

	return { valid, rejected };
}

import type { ReviewFinding } from "../types.ts";

export function validateFindingsHaveEvidence(findings: ReviewFinding[]): {
	valid: ReviewFinding[];
	invalid: ReviewFinding[];
} {
	const valid: ReviewFinding[] = [];
	const invalid: ReviewFinding[] = [];

	for (const finding of findings) {
		if (finding.evidence && typeof finding.evidence === "string" && finding.evidence.trim().length > 0) {
			valid.push(finding);
		} else {
			invalid.push(finding);
		}
	}

	return { valid, invalid };
}

export function formatEvidenceError(finding: ReviewFinding): string {
	return `Finding "${finding.title}" in ${finding.file}:${finding.line} is missing required evidence field.`;
}

import type { ReviewFinding } from "../types.ts";

export function scoreSpecificity(finding: ReviewFinding): number {
	let score = 0;

	// Evidence length (0-0.3)
	const evidenceLen = finding.evidence.trim().length;
	if (evidenceLen > 0) score += 0.1;
	if (evidenceLen > 20) score += 0.1;
	if (evidenceLen > 50) score += 0.1;

	// Code snippet presence (0-0.3)
	if (containsCodeSnippet(finding.evidence)) score += 0.15;
	if (containsCodeSnippet(finding.suggestion)) score += 0.15;

	// Line reference (0-0.2)
	if (finding.line > 0) score += 0.1;
	if (finding.description.includes(`line ${finding.line}`)) score += 0.1;

	// Description depth (0-0.2)
	if (finding.description.length > 30) score += 0.1;
	if (finding.description.length > 100) score += 0.1;

	return Math.min(1, score);
}

export function isSpecificEnough(finding: ReviewFinding, threshold = 0.3): boolean {
	return scoreSpecificity(finding) >= threshold;
}

function containsCodeSnippet(text: string): boolean {
	// Check for common code indicators
	return /`[^`]+`/.test(text)
		|| /\bfunction\b/.test(text)
		|| /\bconst\b/.test(text)
		|| /\bclass\b/.test(text)
		|| /\bimport\b/.test(text)
		|| /=>/.test(text)
		|| /\(\)/.test(text)
		|| /\{[^}]{5,}\}/.test(text);
}

import type { ReviewFinding, ReviewReport, ReviewSummary, ReportOptions, Severity } from "../types.ts";
import { SEVERITY_BADGES, SEVERITY_ORDER } from "../types.ts";
import { findingsByFile, findingsBySeverity, findingsByCategory, buildSummary } from "./finding.ts";
import { validateFindingsHaveEvidence, formatEvidenceError } from "../quality/evidence-required.ts";
import { rejectGenericFindings } from "../quality/anti-generic.ts";

export function generateReport(
	findings: ReviewFinding[],
	options: ReportOptions,
	perspectives: string[],
): ReviewReport {
	// Quality enforcement
	let processed = findings;
	processed = rejectGenericFindings(processed).valid;
	processed = validateFindingsHaveEvidence(processed).valid;

	const summary = buildSummary(processed, perspectives);

	return {
		findings: processed,
		summary,
		timestamp: new Date().toISOString(),
		perspectives,
		options,
	};
}

export function formatReport(report: ReviewReport): string {
	switch (report.options.format) {
		case "json":
			return JSON.stringify(report, null, 2);
		case "summary":
			return formatSummary(report);
		case "markdown":
		default:
			return formatMarkdown(report);
	}
}

function formatMarkdown(report: ReviewReport): string {
	const lines: string[] = [];
	lines.push("# Code Review Report");
	lines.push("");
	lines.push(`**Date:** ${report.timestamp}`);
	lines.push(`**Perspectives:** ${report.perspectives.join(", ")}`);
	lines.push("");

	// Summary
	lines.push("## Summary");
	lines.push(`- **Total findings:** ${report.summary.total}`);
	for (const [sev, count] of Object.entries(report.summary.bySeverity)) {
		if (count > 0) {
			lines.push(`- ${SEVERITY_BADGES[sev as Severity]} ${sev}: ${count}`);
		}
	}
	lines.push("");

	// Group findings
	switch (report.options.groupBy) {
		case "file":
			formatByFile(lines, report);
			break;
		case "perspective":
			formatByPerspective(lines, report);
			break;
		case "severity":
			formatBySeverity(lines, report);
			break;
	}

	return lines.join("\n");
}

function formatByFile(lines: string[], report: ReviewReport): void {
	const grouped = findingsByFile(report.findings);
	lines.push("## Findings by File");
	lines.push("");

	for (const [file, findings] of Object.entries(grouped)) {
		lines.push(`### ${file}`);
		for (const f of findings) {
			lines.push("");
			lines.push(`**${SEVERITY_BADGES[f.severity]} [${f.severity}] ${f.title}**`);
			lines.push(`- Line: ${f.line}`);
			lines.push(`- Category: ${f.category}`);
			lines.push(`- ${f.description}`);
			if (f.evidence) {
				lines.push(`- Evidence: \`${f.evidence}\``);
			}
			if (report.options.includeSuggestions && f.suggestion) {
				lines.push(`- Suggestion: ${f.suggestion}`);
			}
		}
		lines.push("");
	}
}

function formatByPerspective(lines: string[], report: ReviewReport): void {
	const grouped = findingsByCategory(report.findings);
	lines.push("## Findings by Perspective");
	lines.push("");

	for (const [category, findings] of Object.entries(grouped)) {
		lines.push(`### ${category}`);
		for (const f of findings) {
			lines.push("");
			lines.push(`**${SEVERITY_BADGES[f.severity]} [${f.severity}] ${f.title}** (${f.file}:${f.line})`);
			lines.push(`- ${f.description}`);
			if (f.evidence) {
				lines.push(`- Evidence: \`${f.evidence}\``);
			}
			if (report.options.includeSuggestions && f.suggestion) {
				lines.push(`- Suggestion: ${f.suggestion}`);
			}
		}
		lines.push("");
	}
}

function formatBySeverity(lines: string[], report: ReviewReport): void {
	const grouped = findingsBySeverity(report.findings);
	lines.push("## Findings by Severity");
	lines.push("");

	const severityOrder: Severity[] = ["must-fix", "should-fix", "nice-to-have", "info"];
	for (const sev of severityOrder) {
		const findings = grouped[sev];
		if (!findings || findings.length === 0) continue;

		lines.push(`### ${SEVERITY_BADGES[sev]} ${sev.toUpperCase()}`);
		for (const f of findings) {
			lines.push("");
			lines.push(`**${f.title}** (${f.file}:${f.line}) [${f.category}]`);
			lines.push(`- ${f.description}`);
			if (f.evidence) {
				lines.push(`- Evidence: \`${f.evidence}\``);
			}
			if (report.options.includeSuggestions && f.suggestion) {
				lines.push(`- Suggestion: ${f.suggestion}`);
			}
		}
		lines.push("");
	}
}

function formatSummary(report: ReviewReport): string {
	const lines: string[] = [];
	lines.push("## Review Summary");
	lines.push("");
	lines.push(`| Severity | Count |`);
	lines.push(`|----------|-------|`);
	for (const [sev, count] of Object.entries(report.summary.bySeverity)) {
		if (count > 0) {
			lines.push(`| ${SEVERITY_BADGES[sev as Severity]} ${sev} | ${count} |`);
		}
	}
	lines.push("");
	lines.push(`**Total:** ${report.summary.total} findings`);

	if (report.findings.length > 0) {
		lines.push("");
		lines.push("### Top Findings:");
		// Show top 10 by severity
		const sorted = [...report.findings].sort((a, b) => SEVERITY_ORDER[b.severity] - SEVERITY_ORDER[a.severity]);
		for (const f of sorted.slice(0, 10)) {
			lines.push(`- ${SEVERITY_BADGES[f.severity]} ${f.title} (${f.file}:${f.line})`);
		}
	}

	return lines.join("\n");
}

import type { ReviewFinding, ReviewReport, ReportOptions, ReviewExtensionConfig, DiffHunk } from "../types.ts";
import { loadConfig } from "../config.ts";
import { registry } from "../perspectives/registry.ts";
import { extractDiff, extractFileDiff } from "../diff/git-diff.ts";
import { classifyChanges, allHunks } from "../diff/change-analysis.ts";
import { extractContext } from "../diff/context-extractor.ts";
import { calculateImpact, formatImpact } from "../diff/impact-calculator.ts";
import { generateReport, formatReport } from "./report.ts";
import { validateFindingsHaveEvidence } from "../quality/evidence-required.ts";
import { rejectGenericFindings } from "../quality/anti-generic.ts";

// Import all perspectives to trigger registration
import "../perspectives/security.ts";
import "../perspectives/performance.ts";
import "../perspectives/maintainability.ts";
import "../perspectives/style.ts";
import "../perspectives/testing.ts";
import "../perspectives/production.ts";

export interface ReviewDiffOptions {
	base?: string;
	head?: string;
	perspectives?: string[];
	maxFiles?: number;
}

export interface ReviewFileOptions {
	file: string;
	perspectives?: string[];
	context?: "full" | "changed-only";
}

export class ReviewOrchestrator {
	private config: ReviewExtensionConfig;

	constructor(cwd: string) {
		const { config } = loadConfig(cwd);
		this.config = config;
	}

	async reviewDiff(cwd: string, options: ReviewDiffOptions = {}): Promise<ReviewReport> {
		const diff = await extractDiff({
			cwd,
			base: options.base,
			head: options.head,
			maxFiles: options.maxFiles ?? 20,
		});

		const parsed = classifyChanges(diff);
		const hunks = allHunks(parsed);
		const impact = calculateImpact(hunks);

		// Get enabled perspectives
		const perspectiveNames = this.resolvePerspectives(options.perspectives);
		const perspectives = registry.filterByNames(perspectiveNames);

		// Build findings from perspective checklists applied to the diff
		const findings = this.analyzeDiff(parsed, hunks, perspectives.map((p) => p.name), cwd);

		const reportOptions: ReportOptions = {
			format: "markdown",
			groupBy: "file",
			includeSuggestions: true,
		};

		const report = generateReport(findings, reportOptions, perspectiveNames);

		// Attach impact to the report context (embedded in findings description)
		if (impact.criticalPaths.length > 0 || impact.highImpactFiles.length > 0) {
			// Impact info is available for callers
		}

		return report;
	}

	async reviewFile(cwd: string, file: string, options: ReviewFileOptions = { file: "" }): Promise<ReviewReport> {
		const perspectiveNames = this.resolvePerspectives(options.perspectives);
		const perspectives = registry.filterByNames(perspectiveNames);

		let hunks: DiffHunk[];

		if (options.context === "changed-only") {
			const diff = await extractFileDiff(cwd, file, options.base);
			const parsed = classifyChanges(diff);
			hunks = allHunks(parsed);
		} else {
			// Full file — create a synthetic hunk for the whole file
			hunks = [{
				file,
				changeType: "modified",
				oldStart: 1,
				oldCount: 0,
				newStart: 1,
				newCount: 0,
				content: "",
				header: "full file review",
			}];
		}

		// Extract context for the file
		const contexts = extractContext(file, hunks, cwd);

		const findings = this.analyzeFile(file, hunks, perspectives.map((p) => p.name), cwd, contexts);

		const reportOptions: ReportOptions = {
			format: "markdown",
			groupBy: "perspective",
			includeSuggestions: true,
		};

		return generateReport(findings, reportOptions, perspectiveNames);
	}

	generateFormattedReport(
		findings: ReviewFinding[],
		options: ReportOptions,
	): ReviewReport {
		const perspectiveNames = this.resolvePerspectives();
		const report = generateReport(findings, options, perspectiveNames);
		return report;
	}

	private resolvePerspectives(requested?: string[]): string[] {
		if (requested && requested.length > 0) {
			return requested;
		}

		// Use enabled perspectives from config
		return Object.entries(this.config.perspectives)
			.filter(([, cfg]) => cfg.enabled)
			.map(([name]) => name);
	}

	private analyzeDiff(
		parsed: ReturnType<typeof classifyChanges>,
		hunks: DiffHunk[],
		perspectiveNames: string[],
		cwd: string,
	): ReviewFinding[] {
		const findings: ReviewFinding[] = [];

		for (const fileDiff of parsed) {
			const contexts = extractContext(fileDiff.file, fileDiff.hunks, cwd);

			for (const perspectiveName of perspectiveNames) {
				const perspective = registry.get(perspectiveName);
				if (!perspective) continue;

				const promptContext = registry.buildPromptContext(perspective, hunks);

				// Generate checklist-based findings for each hunk
				for (let hunkIdx = 0; hunkIdx < fileDiff.hunks.length; hunkIdx++) {
					const hunk = fileDiff.hunks[hunkIdx]!;
					const ctx = contexts[hunkIdx];

					// Create a structured analysis prompt context for each checklist item
					for (const item of perspective.checklist) {
						const finding = this.evaluateChecklistItem(
							perspectiveName,
							item,
							fileDiff.file,
							hunk.newStart,
							hunk.content,
							ctx,
							perspective.defaultSeverity,
						);
						if (finding) {
							findings.push(finding);
						}
					}
				}
			}
		}

		return findings;
	}

	private analyzeFile(
		file: string,
		hunks: DiffHunk[],
		perspectiveNames: string[],
		cwd: string,
		contexts: ReturnType<typeof extractContext>,
	): ReviewFinding[] {
		const findings: ReviewFinding[] = [];

		for (const perspectiveName of perspectiveNames) {
			const perspective = registry.get(perspectiveName);
			if (!perspective) continue;

			for (const item of perspective.checklist) {
				const line = hunks.length > 0 ? hunks[0]!.newStart : 1;
				const ctx = contexts.length > 0 ? contexts[0] : undefined;
				const hunkContent = hunks.length > 0 ? hunks[0]!.content : "";

				const finding = this.evaluateChecklistItem(
					perspectiveName,
					item,
					file,
					line,
					hunkContent,
					ctx,
					perspective.defaultSeverity,
				);
				if (finding) {
					findings.push(finding);
				}
			}
		}

		return findings;
	}

	private evaluateChecklistItem(
		perspectiveName: string,
		checklistItem: string,
		file: string,
		line: number,
		hunkContent: string,
		context: { beforeLines: string[]; hunkLines: string[]; afterLines: string[] } | undefined,
		defaultSeverity: string,
	): ReviewFinding | null {
		// This is a static analysis placeholder. In a real implementation,
		// the Pi agent would use the checklist item + context to produce findings.
		// For tool registration purposes, we return null (no automatic findings)
		// and let the Pi agent handle the actual review via the prompt context.
		return null;
	}
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";
import { ReviewOrchestrator } from "../review/orchestrator.ts";
import { generateReport, formatReport } from "../review/report.ts";
import { calculateImpact } from "../diff/impact-calculator.ts";
import { classifyChanges, allHunks } from "../diff/change-analysis.ts";

interface ReviewToolResult {
	content: Array<{ type: "text"; text: string }>;
	details: { tool: string; status: "ok" | "error" };
	isError?: boolean;
}

function reviewResult(text: string, isError = false): ReviewToolResult {
	return {
		content: [{ type: "text", text }],
		details: { tool: "pi-review", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

export function registerReviewTools(pi: ExtensionAPI): void {
	// review_diff
	pi.registerTool({
		name: "review_diff",
		label: "Review Diff",
		description: "Review git diff with multi-perspective analysis. Returns findings categorized by security, performance, maintainability, testing, and production readiness.",
		parameters: Type.Object({
			base: Type.Optional(Type.String({ description: "Git base ref (default: HEAD~1 or main)." })),
			head: Type.Optional(Type.String({ description: "Git head ref (default: HEAD)." })),
			perspectives: Type.Optional(Type.Array(Type.String(), { description: "Review perspectives to use. Default: all enabled." })),
			maxFiles: Type.Optional(Type.Number({ description: "Maximum files to review. Default: 20." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { base?: string; head?: string; perspectives?: string[]; maxFiles?: number };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);
				const report = await orchestrator.reviewDiff(ctx.cwd, {
					base: p.base,
					head: p.head,
					perspectives: p.perspectives,
					maxFiles: p.maxFiles,
				});
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// review_file
	pi.registerTool({
		name: "review_file",
		label: "Review File",
		description: "Review a single file with multi-perspective analysis. Use 'full' context for complete file review or 'changed-only' for diff-based review.",
		parameters: Type.Object({
			file: Type.String({ description: "File path to review." }),
			perspectives: Type.Optional(Type.Array(Type.String(), { description: "Review perspectives to use." })),
			context: Type.Optional(Type.String({ description: "'full' for complete file or 'changed-only' for diff. Default: full." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { file: string; perspectives?: string[]; context?: string };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);
				const report = await orchestrator.reviewFile(ctx.cwd, p.file, {
					file: p.file,
					perspectives: p.perspectives,
					context: p.context === "changed-only" ? "changed-only" : "full",
				});
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// review_report
	pi.registerTool({
		name: "review_report",
		label: "Review Report",
		description: "Generate a formatted review report from findings. Supports markdown, JSON, and summary formats.",
		parameters: Type.Object({
			format: Type.Optional(Type.String({ description: "Output format: 'markdown', 'json', or 'summary'. Default: markdown." })),
			includeSuggestions: Type.Optional(Type.Boolean({ description: "Include fix suggestions. Default: true." })),
			groupBy: Type.Optional(Type.String({ description: "Group findings by: 'file', 'perspective', or 'severity'. Default: file." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, ctx) {
			const p = params as { format?: string; includeSuggestions?: boolean; groupBy?: string };
			try {
				const orchestrator = new ReviewOrchestrator(ctx.cwd);

				// Run a diff review first to get current findings
				const diffReport = await orchestrator.reviewDiff(ctx.cwd);
				const report = orchestrator.generateFormattedReport(
					diffReport.findings,
					{
						format: (p.format === "json" ? "json" : p.format === "summary" ? "summary" : "markdown") as "markdown" | "json" | "summary",
						groupBy: (p.groupBy === "perspective" ? "perspective" : p.groupBy === "severity" ? "severity" : "file") as "file" | "perspective" | "severity",
						includeSuggestions: p.includeSuggestions !== false,
					},
				);
				const formatted = formatReport(report);
				return reviewResult(formatted);
			} catch (error) {
				return reviewResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);
}

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerReviewTools } from "./tool-registry.ts";

// Import perspectives to trigger registration side effects
import "../perspectives/security.ts";
import "../perspectives/performance.ts";
import "../perspectives/maintainability.ts";
import "../perspectives/style.ts";
import "../perspectives/testing.ts";
import "../perspectives/production.ts";

export function registerPiReview(pi: ExtensionAPI): void {
	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Register review tools
		registerReviewTools(pi);

		// Register slash commands
		registerReviewCommands(pi, ctx);
	});
}

function registerReviewCommands(pi: ExtensionAPI, ctx: ExtensionContext): void {
	// /review — review recent changes
	pi.registerCommand({
		name: "review",
		label: "Review",
		description: "Review recent code changes with multi-perspective analysis.",
		async execute(args) {
			const arg = args?.trim().toLowerCase() ?? "";
			const { ReviewOrchestrator } = await import("../review/orchestrator.ts");
			const orchestrator = new ReviewOrchestrator(ctx.cwd);

			if (arg === "security") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["security"] });
				const { formatReport } = await import("../review/report.ts");
				return formatReport(report);
			}

			if (arg === "performance") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["performance"] });
				const { formatReport } = await import("../review/report.ts");
				return formatReport(report);
			}

			if (arg === "diff") {
				const report = await orchestrator.reviewDiff(ctx.cwd);
				const { formatReport } = await import("../review/report.ts");
				return formatReport(report);
			}

			if (arg === "report") {
				const report = await orchestrator.reviewDiff(ctx.cwd);
				const tempReport = orchestrator.generateFormattedReport(report.findings, {
					format: "summary",
					groupBy: "severity",
					includeSuggestions: true,
				});
				const { formatReport } = await import("../review/report.ts");
				return formatReport(tempReport);
			}

			if (arg.startsWith("file ")) {
				const file = arg.slice(5).trim();
				if (!file) return "Usage: /review file <path>";
				const report = await orchestrator.reviewFile(ctx.cwd, file, { file });
				const { formatReport } = await import("../review/report.ts");
				return formatReport(report);
			}

			// Default: full review
			const report = await orchestrator.reviewDiff(ctx.cwd);
			const { formatReport } = await import("../review/report.ts");
			return formatReport(report);
		},
	});
}

