describe("classifyChanges", () => {
	test("parses empty diff", () => {
		assert.deepEqual(classifyChanges(""), []);
		assert.deepEqual(classifyChanges("   "), []);
	});

	test("parses multiple files", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		assert.equal(parsed.length, 4);
	});

	test("classifies modified file", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const app = parsed.find((p) => p.file === "src/app.ts");
		assert.ok(app);
		assert.equal(app!.changeType, "modified");
	});

	test("classifies new file", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const newFile = parsed.find((p) => p.file === "src/new-file.ts");
		assert.ok(newFile);
		assert.equal(newFile!.changeType, "new");
	});

	test("classifies deleted file", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const del = parsed.find((p) => p.file === "src/old-file.ts");
		assert.ok(del);
		assert.equal(del!.changeType, "deleted");
	});

	test("classifies renamed file", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const renamed = parsed.find((p) => p.changeType === "renamed");
		assert.ok(renamed);
	});

	test("extracts hunks with correct line numbers", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const app = parsed.find((p) => p.file === "src/app.ts");
		assert.ok(app);
		assert.equal(app!.hunks.length, 1);
		assert.equal(app!.hunks[0]!.oldStart, 10);
		assert.equal(app!.hunks[0]!.newStart, 10);
	});

	test("hunks contain content lines", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const app = parsed.find((p) => p.file === "src/app.ts");
		assert.ok(app);
		const content = app!.hunks[0]!.content;
		assert.ok(content.includes("+  const id = validateId"));
		assert.ok(content.includes("-  db.query"));
	});
});

describe("allHunks", () => {
	test("flattens all hunks from all files", () => {
		const parsed = classifyChanges(SAMPLE_DIFF);
		const hunks = allHunks(parsed);
		assert.ok(hunks.length >= 4);
	});
});

import assert from "node:assert/strict";
import test, { describe } from "node:test";
import { extractContext } from "../../src/diff/context-extractor.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";
import type { DiffHunk } from "../../src/types.ts";

function makeHunk(overrides: Partial<DiffHunk> = {}): DiffHunk {
	return {
		file: "test.ts",
		changeType: "modified",
		oldStart: 1,
		oldCount: 3,
		newStart: 1,
		newCount: 5,
		content: "+line1\n+line2",
		header: "",
		...overrides,
	};
}

describe("extractContext", () => {
	test("extracts context from existing file", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-ctx-"));
		try {
			const filePath = path.join(dir, "test.ts");
			const lines = Array.from({ length: 20 }, (_, i) => `line ${i + 1}`);
			fs.writeFileSync(filePath, lines.join("\n"));

			const hunks = [makeHunk({ file: "test.ts", newStart: 5, newCount: 3 })];
			const contexts = extractContext("test.ts", hunks, dir, 3, 3);

			assert.equal(contexts.length, 1);
			assert.equal(contexts[0]!.hunkIndex, 0);
			assert.ok(contexts[0]!.beforeLines.length <= 3);
			assert.ok(contexts[0]!.hunkLines.length > 0);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("returns empty for non-existent file", () => {
		const hunks = [makeHunk({ file: "nonexistent.ts" })];
		const contexts = extractContext("nonexistent.ts", hunks, "/tmp", 3, 3);
		assert.equal(contexts.length, 0);
	});

	test("handles hunk at start of file", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-ctx-"));
		try {
			const filePath = path.join(dir, "test.ts");
			fs.writeFileSync(filePath, "first line\nsecond line\nthird line\n");

			const hunks = [makeHunk({ file: "test.ts", newStart: 1, newCount: 2 })];
			const contexts = extractContext("test.ts", hunks, dir, 5, 5);

			assert.equal(contexts.length, 1);
			assert.equal(contexts[0]!.beforeLines.length, 0);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("handles multiple hunks", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-ctx-"));
		try {
			const filePath = path.join(dir, "test.ts");
			const lines = Array.from({ length: 50 }, (_, i) => `line ${i + 1}`);
			fs.writeFileSync(filePath, lines.join("\n"));

			const hunks = [
				makeHunk({ file: "test.ts", newStart: 5, newCount: 3 }),
				makeHunk({ file: "test.ts", newStart: 30, newCount: 5 }),
			];
			const contexts = extractContext("test.ts", hunks, dir, 2, 2);

			assert.equal(contexts.length, 2);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});
});

import assert from "node:assert/strict";
import test, { describe } from "node:test";
import { calculateImpact, formatImpact } from "../../src/diff/impact-calculator.ts";
import type { DiffHunk } from "../../src/types.ts";

function makeHunk(file: string, content: string, changeType: "new" | "modified" | "deleted" | "renamed" = "modified"): DiffHunk {
	return {
		file,
		changeType,
		oldStart: 1,
		oldCount: 0,
		newStart: 1,
		newCount: 0,
		content,
		header: "",
	};
}

describe("calculateImpact", () => {
	test("empty hunks produce zero impact", () => {
		const impact = calculateImpact([]);
		assert.equal(impact.filesChanged, 0);
		assert.equal(impact.linesAdded, 0);
		assert.equal(impact.linesRemoved, 0);
	});

	test("counts added and removed lines", () => {
		const hunks = [
			makeHunk("a.ts", "+line1\n+line2\n-line3\n-line4\n-line5"),
		];
		const impact = calculateImpact(hunks);
		assert.equal(impact.linesAdded, 2);
		assert.equal(impact.linesRemoved, 3);
	});

	test("counts unique files", () => {
		const hunks = [
			makeHunk("a.ts", "+a"),
			makeHunk("b.ts", "+b"),
			makeHunk("a.ts", "+c"),
		];
		const impact = calculateImpact(hunks);
		assert.equal(impact.filesChanged, 2);
	});

	test("identifies critical paths", () => {
		const hunks = [
			makeHunk("src/auth/login.ts", "+code"),
			makeHunk("src/utils/helper.ts", "+code"),
		];
		const impact = calculateImpact(hunks);
		assert.ok(impact.criticalPaths.includes("src/auth/login.ts"));
		assert.ok(!impact.criticalPaths.includes("src/utils/helper.ts"));
	});

	test("identifies high impact files (>50 changes)", () => {
		const manyChanges = Array.from({ length: 55 }, () => "+line").join("\n");
		const hunks = [
			makeHunk("big-file.ts", manyChanges),
		];
		const impact = calculateImpact(hunks);
		assert.ok(impact.highImpactFiles.includes("big-file.ts"));
	});

	test("does not count +++ or --- header lines", () => {
		const hunks = [
			makeHunk("a.ts", "+++ b/a.ts\n--- a/a.ts\n+real line"),
		];
		const impact = calculateImpact(hunks);
		assert.equal(impact.linesAdded, 1);
		assert.equal(impact.linesRemoved, 0);
	});
});

describe("formatImpact", () => {
	test("formats basic impact", () => {
		const impact = calculateImpact([
			makeHunk("a.ts", "+line1\n-line2"),
		]);
		const text = formatImpact(impact);
		assert.ok(text.includes("Files changed: 1"));
		assert.ok(text.includes("+1"));
		assert.ok(text.includes("-1"));
	});

	test("includes critical paths warning", () => {
		const impact = calculateImpact([
			makeHunk("src/auth/session.ts", "+code"),
		]);
		const text = formatImpact(impact);
		assert.ok(text.includes("Critical paths"));
	});
});

import assert from "node:assert/strict";
import test, { describe } from "node:test";
import { generateReport, formatReport } from "../../src/review/report.ts";
import type { ReviewFinding, ReportOptions, ReviewReport } from "../../src/types.ts";

function makeFinding(overrides: Partial<ReviewFinding> = {}): ReviewFinding {
	return {
		file: "src/app.ts",
		line: 10,
		severity: "must-fix",
		category: "security",
		title: "SQL Injection",
		description: "User input used directly in SQL query without parameterization",
		evidence: "db.query(`SELECT * FROM users WHERE id = ${id}`)",
		suggestion: "Use parameterized queries: db.query('SELECT * FROM users WHERE id = $1', [id])",
		...overrides,
	};
}

const SAMPLE_FINDINGS: ReviewFinding[] = [
	makeFinding(),
	makeFinding({ file: "src/app.ts", line: 25, severity: "should-fix", category: "performance", title: "N+1 Query", description: "Loop makes individual DB queries", evidence: "for (const u of users) { db.find(u.id) }", suggestion: "Batch the query" }),
	makeFinding({ file: "src/util.ts", line: 5, severity: "nice-to-have", category: "style", title: "Inconsistent naming", description: "Variable uses snake_case in camelCase project", evidence: "const user_name = getName()", suggestion: "Use userName" }),
];

describe("generateReport", () => {
	test("filters out findings without evidence", () => {
		const findings = [
			makeFinding({ evidence: "valid evidence" }),
			makeFinding({ evidence: "", title: "No evidence" }),
		];
		const report = generateReport(findings, { format: "markdown", groupBy: "file", includeSuggestions: true }, ["security"]);
		assert.equal(report.findings.length, 1);
		assert.equal(report.findings[0]!.title, "SQL Injection");
	});

	test("builds summary with correct counts", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "markdown", groupBy: "file", includeSuggestions: true }, ["security", "performance"]);
		assert.equal(report.summary.total, 3);
		assert.equal(report.summary.bySeverity["must-fix"], 1);
		assert.equal(report.summary.bySeverity["should-fix"], 1);
		assert.equal(report.summary.bySeverity["nice-to-have"], 1);
	});

	test("sets timestamp", () => {
		const report = generateReport([], { format: "markdown", groupBy: "file", includeSuggestions: true }, []);
		assert.ok(report.timestamp);
	});
});

describe("formatReport - markdown", () => {
	test("group by file", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "markdown", groupBy: "file", includeSuggestions: true }, ["security"]);
		const text = formatReport(report);
		assert.ok(text.includes("Code Review Report"));
		assert.ok(text.includes("src/app.ts"));
		assert.ok(text.includes("src/util.ts"));
		assert.ok(text.includes("SQL Injection"));
	});

	test("group by severity", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "markdown", groupBy: "severity", includeSuggestions: true }, ["security"]);
		const text = formatReport(report);
		assert.ok(text.includes("MUST-FIX"));
		assert.ok(text.includes("SHOULD-FIX"));
	});

	test("group by perspective", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "markdown", groupBy: "perspective", includeSuggestions: true }, ["security"]);
		const text = formatReport(report);
		assert.ok(text.includes("security"));
		assert.ok(text.includes("performance"));
	});

	test("omits suggestions when disabled", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "markdown", groupBy: "file", includeSuggestions: false }, ["security"]);
		const text = formatReport(report);
		assert.ok(!text.includes("Suggestion:"));
	});
});

describe("formatReport - json", () => {
	test("outputs valid JSON", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "json", groupBy: "file", includeSuggestions: true }, ["security"]);
		const text = formatReport(report);
		const parsed = JSON.parse(text);
		assert.ok(parsed.findings);
		assert.ok(parsed.summary);
	});
});

describe("formatReport - summary", () => {
	test("produces concise table", () => {
		const report = generateReport(SAMPLE_FINDINGS, { format: "summary", groupBy: "severity", includeSuggestions: true }, ["security"]);
		const text = formatReport(report);
		assert.ok(text.includes("Review Summary"));
		assert.ok(text.includes("Total"));
	});
});

describe("formatReport - empty findings", () => {
	test("handles empty findings gracefully", () => {
		const report = generateReport([], { format: "markdown", groupBy: "file", includeSuggestions: true }, []);
		const text = formatReport(report);
		assert.ok(text.includes("Total findings: 0"));
	});
});

