		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			const orchestrator = new ReviewOrchestrator(dir);
			assert.ok(orchestrator);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("resolvePerspectives defaults to enabled perspectives", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			const orchestrator = new ReviewOrchestrator(dir);
			// Access private method via cast
			const report = orchestrator.generateFormattedReport([], {
				format: "markdown",
				groupBy: "file",
				includeSuggestions: true,
			});
			assert.ok(report);
			assert.equal(report.findings.length, 0);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("reviewDiff returns a report structure", async () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			// Initialize a git repo
			fs.writeFileSync(path.join(dir, "test.txt"), "hello\n");
			const { execSync } = await import("node:child_process");
			execSync("git init", { cwd: dir });
			execSync("git config user.email test@test.com", { cwd: dir });
			execSync("git config user.name Test", { cwd: dir });
			execSync("git add .", { cwd: dir });
			execSync("git commit -m initial", { cwd: dir });

			// Make a change
			fs.writeFileSync(path.join(dir, "test.txt"), "hello world\n");
			execSync("git add .", { cwd: dir });
			execSync("git commit -m change", { cwd: dir });

			const orchestrator = new ReviewOrchestrator(dir);
			const report = await orchestrator.reviewDiff(dir, { base: "HEAD~1", head: "HEAD" });

			assert.ok(report);
			assert.ok(report.timestamp);
			assert.ok(report.perspectives);
			assert.ok(report.summary);
			assert.ok(Array.isArray(report.findings));
		} finally {
			fs.rmSync(dir, { recursive: true, force: true });
		}
	});
});

